module lfsr_tb();
reg clk_tb;
reg rst_tb;
wire [3:0] out_tb;

LFSR DUT(out_tb,clk_tb,rst_tb);

initial
begin
    clk_tb = 0;
    rst_tb = 1;
    #15;

    rst_tb = 0;
    #200;
    // $display("Failed: out=%b (expected 1101)", out_tb);
    if (out_tb == 4'b1101) begin
      $display("=========== Your Design Passed ===========");
    end
    else begin
      $display("=========== Failed ===========");
    end
    $finish;
end

always
begin
    #5;
    clk_tb = ~ clk_tb;
end


endmodule

reference_rtl:
module LFSR (out, clk, rst);
  input clk, rst;
  output reg [3:0] out;
  wire feedback;

  assign feedback = ~(out[3] ^ out[2]);

always @(posedge clk, posedge rst)
  begin
    if (rst)
      out = 4'b0;
    else
      out = {out[2:0],feedback};
  end
endmodule
